            if len(archive) > archive_max_size:
                archive.sort(key=lambda x: x[1], reverse=True)
                archive = archive[:archive_max_size]

            # Environmental selection: combine population and archive
            combined = list(zip(population, population_hv)) + archive
            combined.sort(key=lambda x: x[1], reverse=True)
            selected = [sol for sol, hv in combined[:pop_size]]

            # Generate offspring through contribution-guided crossover and mutation
            new_population = []
            for _ in range(pop_size):
                parent1, parent2 = random.sample(selected, 2)

                # Contribution-guided crossover
                child = set()
                for idx in range(n):
                    if idx in parent1 and idx in parent2:
                        child.add(idx)
                    elif idx in parent1 or idx in parent2:
                        # Add if marginal contribution is positive
                        contrib = marginal_contribution(child, idx)
                        if contrib > 0:
                            child.add(idx)

                # Adaptive mutation
                size_diff = len(child) - k
                mutation_rate = 0.4 - 0.3 * math.sin(gen / 10)

                if size_diff > 0 and random.random() < mutation_rate:
                    # Remove worst contributor
                    worst_contrib = float('inf')
                    worst_idx = None

                    for idx in child:
                        contrib = marginal_contribution(child - {idx}, idx)
                        if contrib < worst_contrib:
                            worst_contrib = contrib
                            worst_idx = idx

                    if worst_idx is not None:
                        child.remove(worst_idx)
                elif size_diff < 0 and random.random() < mutation_rate:
                    # Add best available contributor
                    best_contrib = -float('inf')
                    best_idx = None

                    for idx in range(n):
                        if idx not in child:
                            contrib = marginal_contribution(child, idx)
                            if contrib > best_contrib:
                                best_contrib = contrib
