    # 3. Contribution-guided local swap refinement
    def local_swap_refinement(solution: Set[int], max_iter: int = 20) -> Set[int]:
        """Local refinement using contribution-guided swaps"""
        current_set = solution.copy()
        current_hv = compute_hv(current_set)

